# tests/test_sanitizer.py
import pytest
import json
import os
from security.sanitizer import sanitize_html


class TestBasicSanitization:
    """Test that safe HTML tags are preserved."""

    def test_allows_bold_tags(self):
        assert sanitize_html("<b>bold text</b>") == "<b>bold text</b>"

    def test_allows_italic_tags(self):
        assert sanitize_html("<i>italic text</i>") == "<i>italic text</i>"

    def test_allows_em_tags(self):
        assert sanitize_html("<em>emphasized</em>") == "<em>emphasized</em>"

    def test_allows_strong_tags(self):
        assert sanitize_html("<strong>strong text</strong>") == "<strong>strong text</strong>"

    def test_allows_links_with_http(self):
        result = sanitize_html('<a href="https://example.com">link</a>')
        assert 'href="https://example.com"' in result
        assert '<a ' in result
        assert 'link</a>' in result

    def test_allows_unordered_lists(self):
        html = "<ul><li>item 1</li><li>item 2</li></ul>"
        assert sanitize_html(html) == html

    def test_allows_ordered_lists(self):
        html = "<ol><li>item 1</li><li>item 2</li></ol>"
        assert sanitize_html(html) == html

    def test_allows_paragraphs(self):
        assert sanitize_html("<p>paragraph</p>") == "<p>paragraph</p>"

    def test_allows_line_breaks(self):
        result = sanitize_html("line 1<br>line 2")
        assert "<br" in result
        assert "line 1" in result
        assert "line 2" in result

    def test_preserves_plain_text(self):
        assert sanitize_html("just plain text") == "just plain text"

    def test_empty_string(self):
        assert sanitize_html("") == ""


class TestCommonXSSVectors:
    """Test stripping of common XSS attack vectors."""

    def test_strips_script_tags(self):
        result = sanitize_html('<script>alert("xss")</script>')
        assert '<script' not in result.lower()
        assert 'alert' not in result.lower()

    def test_strips_script_tags_with_src(self):
        result = sanitize_html('<script src="https://evil.com/xss.js"></script>')
        assert '<script' not in result.lower()

    def test_strips_onclick_handler(self):
        result = sanitize_html('<div onclick="alert(1)">click me</div>')
        assert 'onclick' not in result.lower()

    def test_strips_onerror_handler(self):
        result = sanitize_html('<img onerror="alert(1)" src="x">')
        assert 'onerror' not in result.lower()

    def test_strips_onload_handler(self):
        result = sanitize_html('<body onload="alert(1)">')
        assert 'onload' not in result.lower()

    def test_strips_onmouseover_handler(self):
        result = sanitize_html('<div onmouseover="alert(1)">hover</div>')
        assert 'onmouseover' not in result.lower()

    def test_strips_javascript_url_in_href(self):
        result = sanitize_html('<a href="javascript:alert(1)">link</a>')
        assert 'javascript:' not in result.lower()

    def test_strips_javascript_url_with_whitespace(self):
        result = sanitize_html('<a href="  javascript:alert(1)">link</a>')
        assert 'javascript' not in result.lower()

    def test_strips_javascript_url_mixed_case(self):
        result = sanitize_html('<a href="JaVaScRiPt:alert(1)">link</a>')
        assert 'javascript' not in result.lower()

    def test_strips_img_tags(self):
        result = sanitize_html('<img src="x" onerror="alert(1)">')
        assert '<img' not in result.lower()

    def test_strips_iframe_tags(self):
        result = sanitize_html('<iframe src="https://evil.com"></iframe>')
        assert '<iframe' not in result.lower()

    def test_strips_object_tags(self):
        result = sanitize_html('<object data="data:text/html,<script>alert(1)</script>"></object>')
        assert '<object' not in result.lower()

    def test_strips_embed_tags(self):
        result = sanitize_html('<embed src="https://evil.com/xss.swf">')
        assert '<embed' not in result.lower()

    def test_strips_form_tags(self):
        result = sanitize_html('<form action="https://evil.com"><input type="submit"></form>')
        assert '<form' not in result.lower()


class TestSVGXSSVectors:
    """Test stripping of SVG-based XSS vectors — security audit priority."""

    def test_strips_svg_with_onload(self):
        result = sanitize_html('<svg onload="alert(1)">')
        assert '<svg' not in result.lower()
        assert 'onload' not in result.lower()

    def test_strips_svg_script_element(self):
        result = sanitize_html('<svg><script>alert(1)</script></svg>')
        assert '<svg' not in result.lower()
        assert '<script' not in result.lower()

    def test_strips_svg_animate(self):
        result = sanitize_html('<svg><animate onbegin="alert(1)" attributeName="x"></animate></svg>')
        assert '<svg' not in result.lower()
        assert 'onbegin' not in result.lower()

    def test_strips_svg_set(self):
        result = sanitize_html('<svg><set onbegin="alert(1)" attributeName="x" to="1"></set></svg>')
        assert '<svg' not in result.lower()
        assert 'onbegin' not in result.lower()

    def test_strips_svg_foreignobject(self):
        result = sanitize_html('<svg><foreignObject><body onload="alert(1)"></body></foreignObject></svg>')
        assert '<svg' not in result.lower()
        assert 'foreignobject' not in result.lower()

    def test_strips_svg_use_with_external_ref(self):
        result = sanitize_html('<svg><use href="https://evil.com/xss.svg#payload"></use></svg>')
        assert '<svg' not in result.lower()

    def test_strips_math_elements(self):
        result = sanitize_html('<math><maction actiontype="statusline#" xlink:href="javascript:alert(1)">click</maction></math>')
        assert '<math' not in result.lower()
        assert 'javascript' not in result.lower()


class TestCSSExpressionXSS:
    """Test stripping of CSS expression-based XSS — security audit priority."""

    def test_strips_style_with_expression(self):
        result = sanitize_html('<div style="width: expression(alert(1))">test</div>')
        assert 'expression' not in result.lower()

    def test_strips_style_with_url_javascript(self):
        result = sanitize_html('<div style="background: url(javascript:alert(1))">test</div>')
        assert 'javascript' not in result.lower()

    def test_strips_style_tag(self):
        result = sanitize_html('<style>body { background: url(javascript:alert(1)) }</style>')
        assert '<style' not in result.lower()

    def test_strips_style_with_moz_binding(self):
        result = sanitize_html('<div style="-moz-binding: url(https://evil.com/xss.xml#xss)">test</div>')
        assert '-moz-binding' not in result.lower()

    def test_strips_style_with_behavior(self):
        result = sanitize_html('<div style="behavior: url(xss.htc)">test</div>')
        assert 'behavior' not in result.lower()

    def test_strips_style_expression_with_comments(self):
        result = sanitize_html('<div style="width: expr/*XSS*/ession(alert(1))">test</div>')
        assert 'expr' not in result.lower() or 'ession' not in result.lower()

    def test_strips_style_attribute_entirely_if_dangerous(self):
        result = sanitize_html('<p style="color: red; background: expression(alert(1))">text</p>')
        assert 'expression' not in result.lower()


class TestEdgeCases:
    """Test edge cases and encoding tricks."""

    def test_strips_null_bytes_in_tags(self):
        result = sanitize_html('<scr\x00ipt>alert(1)</script>')
        assert 'alert' not in result.lower()

    def test_handles_nested_dangerous_content(self):
        result = sanitize_html('<b><script>alert(1)</script></b>')
        assert '<script' not in result.lower()
        assert '<b>' in result

    def test_strips_data_url_scheme(self):
        result = sanitize_html('<a href="data:text/html,<script>alert(1)</script>">click</a>')
        assert 'data:' not in result.lower() or '<script' not in result.lower()

    def test_strips_vbscript_url(self):
        result = sanitize_html('<a href="vbscript:alert(1)">click</a>')
        assert 'vbscript' not in result.lower()

    def test_handles_malformed_html(self):
        # Should not crash on malformed input
        result = sanitize_html('<b><i>unclosed tags<script>alert(1)')
        assert '<script' not in result.lower()

    def test_handles_entities_in_attributes(self):
        result = sanitize_html('<a href="&#106;&#97;&#118;&#97;&#115;&#99;&#114;&#105;&#112;&#116;&#58;alert(1)">link</a>')
        assert 'javascript' not in result.lower() or 'alert' not in result.lower()

    def test_strips_base_tag(self):
        result = sanitize_html('<base href="https://evil.com/">')
        assert '<base' not in result.lower()

    def test_strips_meta_tag(self):
        result = sanitize_html('<meta http-equiv="refresh" content="0;url=javascript:alert(1)">')
        assert '<meta' not in result.lower()


